-- 006: Bulk species data insert (2026-07-06)
-- Comprehensive species for Seoul 21 rivers

-- Drop unique constraint on inaturalist_id (same species can appear in multiple rivers)
ALTER TABLE species_observations DROP CONSTRAINT IF EXISTS uq_species_inat_id;

-- Ensure INSERT policy exists for citizen reports
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='species_observations' AND policyname='so_insert') THEN
    CREATE POLICY "so_insert" ON species_observations FOR INSERT WITH CHECK (true);
  END IF;
END $$;

